const ALLOWED_LANGS=["en","ru","hy"];let currentLangData=null;const prices={document:1,website:2,subtitles:3,certified:5,interpretation:10,other:0};async function setLanguage(e){if(!ALLOWED_LANGS.includes(e))return;const t=await fetch(`../../data/${e}.json`);if(!t.ok)return;const n=await t.json();document.getElementById("page-title").textContent=n.pageTitle,document.getElementById("page-description").textContent=n.pageDescription,document.getElementById("label-service").textContent=n.labelService,document.getElementById("label-description").textContent=n.labelDescription,document.getElementById("submit-button").textContent=n.submitButton,currentLangData=n,updateTotal()}function updateTotal(){const e=document.querySelectorAll('select[name="service"]');let t=0;e.forEach(e=>{t+=prices[e.value]||0});const n=currentLangData?.totalPrice||"Your total price is: $";document.getElementById("total-price").textContent=n+t}function addRequest(){const e=document.getElementById("requests-container"),t=document.querySelector(".request-block").cloneNode(!0);t.querySelectorAll("input[id], select[id], textarea[id], button[id]").forEach(e=>e.removeAttribute("id")),t.querySelector("textarea").value="";const n=t.querySelector("select");n.selectedIndex=0,n.addEventListener("change",updateTotal);const a=t.querySelector(".request-buttons"),o=document.createElement("button");o.type="button",o.className="add-btn",o.textContent="+",o.addEventListener("click",addRequest);const r=document.createElement("button");for(r.type="button",r.className="remove-btn",r.textContent="−",r.addEventListener("click",()=>removeRequest(r));a.firstChild;)a.removeChild(a.firstChild);a.appendChild(o),a.appendChild(r),e.appendChild(t),updateTotal()}function removeRequest(e){e.closest(".request-block").remove(),updateTotal()}function validateAndSubmit(e){const t=document.querySelectorAll('textarea[name="description"]');Array.from(t).some(e=>e.value.trim())||(e.preventDefault(),alert(currentLangData?.validationError||"Please describe at least one request."))}window.addEventListener("load",()=>{setLanguage("en"),document.querySelectorAll(".lang-icon[data-lang]").forEach(e=>{e.addEventListener("click",()=>setLanguage(e.dataset.lang)),e.addEventListener("keydown",t=>{"Enter"!==t.key&&" "!==t.key||(t.preventDefault(),setLanguage(e.dataset.lang))})}),document.getElementById("request-form").addEventListener("submit",validateAndSubmit),document.querySelector(".request-buttons .add-btn").addEventListener("click",addRequest),document.querySelector('select[name="service"]').addEventListener("change",updateTotal)});